//
//  CarouselDoodles.swift
//  Joodle
//
//  Real doodles used as the glyphs in the Pro feature carousel's year grid, in
//  place of the synthetic mushroom outline. Points are in 342×342 canvas space
//  (DOODLE_CANVAS_SIZE); the grid fits each doodle's bounds into its cell.
//
//  Data is a base64-encoded JSON array of doodles (88 entries), each an array of
//  {points, isDot} paths, downsampled from the exported originals — imperceptible at
//  grid scale but keeps the embedded payload small.
//

import CoreGraphics
import Foundation

/// A real doodle with its precomputed bounds, so the grid can fit-and-center it
/// into a cell without recomputing the bounding box every frame.
struct CarouselDoodle {
  let paths: [DoodlePathData]
  let bounds: CGRect
}

/// The doodles, decoded once. Falls back to an empty list if decoding ever fails
/// (the grid then simply draws empty dots).
let CAROUSEL_DOODLES: [CarouselDoodle] = {
  guard let data = Data(base64Encoded: CAROUSEL_DOODLE_DATA_B64, options: .ignoreUnknownCharacters),
        let decoded = try? JSONDecoder().decode([[DoodlePathData]].self, from: data)
  else { return [] }
  return decoded.map { paths in
    let points = paths.flatMap(\.points)
    let xs = points.map(\.x)
    let ys = points.map(\.y)
    let minX = xs.min() ?? 0, maxX = xs.max() ?? 0
    let minY = ys.min() ?? 0, maxY = ys.max() ?? 0
    let bounds = CGRect(x: minX, y: minY, width: maxX - minX, height: maxY - minY)
    return CarouselDoodle(paths: paths, bounds: bounds)
  }
}()

